// Get current BTC mid price to calculate size
const symbol = $node['DCA Configuration'].json.symbol;
const quoteSize = parseFloat($node['DCA Configuration'].json.quoteSize);

console.log(`📊 Fetching ${symbol} price to calculate order size`);

return {
  symbol,
  quoteSize,
  timestamp: Date.now()
};

// Calculate order size based on quote amount and current price
const symbol = $node['Prepare Price Check'].json.symbol;
const quoteSize = $node['Prepare Price Check'].json.quoteSize;
const allMids = $json;

const currentPrice = parseFloat(allMids[symbol]);

if (!currentPrice || currentPrice <= 0) {
  throw new Error(`Invalid price for ${symbol}: ${currentPrice}`);
}

// Calculate size (amount of BTC to buy)
const size = quoteSize / currentPrice;

console.log(`💰 ${symbol} Price: $${currentPrice}`);
console.log(`📦 Order Size: ${size.toFixed(6)} ${symbol}`);
console.log(`💵 Quote Amount: $${quoteSize}`);

retun {
  symbol,
  side: 'BUY',
  orderType: 'market',
  size: size.toFixed(6),
  currentPrice,
  quoteSize
};

// Log successful DCA execution
const config = $node['DCA Configuration'].json;
const orderCalc = $node['Calculate Order Size'].json;
const result = $json;

const logEntry = {
  success: true,
  timestamp: new Date().toISOString(),
  userId: config.userId,
  symbol: orderCalc.symbol,
  side: orderCalc.side,
  orderType: orderCalc.orderType,
  size: orderCalc.size,
  currentPrice: orderCalc.currentPrice,
  quoteAmount: orderCalc.quoteSize,
  estimatedCost: `$${orderCalc.quoteSize}`,
  orderId: result.result?.response?.data?.statuses?.[0]?.resting?.oid || 'N/A',
  executionId: $execution.id
};

console.log('✅ DCA Order Executed Successfully');
console.log(JSON.stringify(logEntry, null, 2));

return logEntry;

// Log DCA failure
const error = $json.error || 'Unknown error';

console.error('❌ DCA Order Failed:', error);

return {
  success: false,
  timestamp: new Date().toISOString(),
  error: error,
  executionId: $execution.id
};
